#!/bin/bash\n\n# Build script for PyInstaller packaging\n\nPYTHON_VERSION="$(python3 --version | cut -d ' ' -f 2)"\nPACKAGE_NAME="your_package_name"  # Replace with your package name\nOUTPUT_NAME="your_output_name"  # Replace with desired output name\n\n# Create a distribution directory\nmkdir -p dist\n\n# Package the application using PyInstaller\npyinstaller --onefile --name "$OUTPUT_NAME" "$PACKAGE_NAME.py"  # Ensure your script is named correctly\n\n# Move the build to the distribution folder\nmv dist/$OUTPUT_NAME ./dist/\n\necho "Build completed successfully!"\n